VALUES
  ('optometrist-moex-02744', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '如果一開始沒有用散光鏡片矯正，使用交叉圓柱鏡檢測時，何者最為正確？', '["如果交叉圓柱鏡的軸放在090與180，翻轉鏡片，清晰度是相同的，表示沒有散光", "如果交叉圓柱鏡的軸放在045與135，翻轉鏡片，清晰度是相同的，表示沒有散光", "如果交叉圓柱鏡的軸放在090與180，翻轉鏡片，清晰度是相同的；放在045與135，翻轉鏡片，清晰 度又是相同的，表示沒有散光", "若不知有沒有散光，就無法使用交叉圓柱鏡"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "ae2822526472", "answer_pdf_sha1": "7e0d017a64f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02745', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '以交叉圓柱鏡檢驗法調整驗光度-2.50DS/-0.75DC×180的散光軸時，被檢者認為正圓柱鏡軸在135度時， 看得較清楚，則需調整為下列何種屈光度？', '["-2.50DS/-0.75DC×010", "-2.50DS/-0.75DC×170", "-2.50DS/-0.75DC×180", "-2.50DS/-0.50DC×170"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "ae2822526472", "answer_pdf_sha1": "7e0d017a64f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02746', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '以交叉圓柱鏡檢驗法驗光修正-2.00DS/-1.75DC×080的散光軸時，比較負圓柱鏡的軸在35度及125度時， 軸的調整是以5度為一單位。若被檢者的反應在35度時的位置較清楚，則散光軸修正為多少度？', '["40度", "120度", "75度", "85度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "ae2822526472", "answer_pdf_sha1": "7e0d017a64f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02747', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '運用裂隙片驗光（stenopaic slits）幫受檢者驗出矯正度數為+1.00DS/-3.00DC×140。還原當時檢查的過程， 裂隙片放置的兩個角度及矯正度數為下列何者？', '["裂隙片在50度時矯正鏡片的度數為+1.00 DS，在140度時矯正鏡片的度數為-2.00 DS", "裂隙片在50度時矯正鏡片的度數為+1.00 DS，在140度時矯正鏡片的度數為-3.00 DS", "裂隙片在50度時矯正鏡片的度數為-2.00 DS，在140度時矯正鏡片的度數為+1.00 DS", "裂隙片在50度時矯正鏡片的度數為-3.00 DS，在140度時矯正鏡片的度數為+1.00 DS"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "ae2822526472", "answer_pdf_sha1": "7e0d017a64f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02748', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '使用裂隙片矯正視力：裂隙放在180度方向，最佳矯正鏡片度數為+1.00 D；裂隙放在90度方向，最佳矯 正鏡片度數為-1.50 D；拿開裂隙片時，受檢者最合適的矯正鏡片度數是：', '["+1.00DS/-2.50DC×090", "+1.00DS/-2.50DC×180", "+1.00DS/-1.50DC×090", "+1.00DS/-1.50DC×180"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "ae2822526472", "answer_pdf_sha1": "7e0d017a64f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02749', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', 'LogMAR 0.3的視力相當於多少的Snellen（史耐倫）與Decimal（小數）？', '["20/60，0.3", "6/18，0.5", "20/40，0.3", "6/12，0.5"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "ae2822526472", "answer_pdf_sha1": "7e0d017a64f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02750', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關屈光不正，下列敘述何者正確？', '["遠視的人沒有遠點（far point）", "近視20屈光度（-20.00 D）的人，在眼球調節放鬆（accommodation relaxed）的狀態下，其遠點位在其 眼前5 cm", "散光的人有兩個焦點（focal points）", "散光的人可以用凸透鏡矯正"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "ae2822526472", "answer_pdf_sha1": "7e0d017a64f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02751', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關各項視力值量測之敘述，下列何者錯誤？', '["針孔視力（pinhole acuity）於戴鏡視力值低於20/30時需進行檢測", "LogMAR視力值健康成人之正常期望值為1.0或更佳", "LogMAR視力表上每單一個字母代表0.02之視力值", "Lea符號（Lea symbols）視力表可應用於不認識英文字母的受測者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "ae2822526472", "answer_pdf_sha1": "7e0d017a64f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02752', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '在進行融像性交叉圓柱鏡測試（fused cross cylinder, FCC）時，若受測者回報垂直線條與水平線條清晰度 一致，則下列有關最小模糊圈、焦線的敘述何者正確？', '["最小模糊圈落於視網膜前，垂直焦線落於視網膜後", "最小模糊圈落於視網膜上，水平焦線落於視網膜前", "最小模糊圈落於視網膜上，垂直焦線落於視網膜前", "最小模糊圈落於視網膜後，水平焦線落於視網膜後"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "ae2822526472", "answer_pdf_sha1": "7e0d017a64f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02753', 'optometrist', 'optometrist-moex-107-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '受檢者有遠視+2.25 D，接受近距離視力檢查，先以0.25 D為一級逐漸增加凸透鏡度數達到+4.25 D時， 受檢者無法再看清楚視標，再逐漸以0.25 D為一級減少凸透鏡度數達到+1.75 D時，受檢者也無法看清楚 視標，根據以上的結果，最合適的近距離加入度（near ADD）為：', '["+0.50 D", "+0.75 D", "+1.25 D", "+1.75 D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:53+00:00", "source_pdf_sha1": "ae2822526472", "answer_pdf_sha1": "7e0d017a64f4", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
